import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { DIALOG_CONTEXT, type DialogContext } from './dialog.context';

let _dialogIdCounter = 0;

@Component({
  selector: 'n-dialog',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents', 'data-slot': 'root' },
  providers: [
    {
      provide: DIALOG_CONTEXT,
      useFactory: (c: DialogComponent) => c.context,
      deps: [forwardRef(() => DialogComponent)],
    },
  ],
})
export class DialogComponent {
  readonly nOpen       = model<boolean>(false);
  readonly nId         = input<string>('');
  readonly nPersistent = input<boolean>(false);
  readonly nRole       = input<'dialog' | 'alertdialog'>('dialog');

  readonly nOpenChange = output<boolean>();

  private readonly _staticId  = `n-dialog-${++_dialogIdCounter}`;
  private readonly _triggerEl = signal<HTMLElement | null>(null);

  readonly dialogId      = computed(() => this.nId() || this._staticId);
  readonly titleId       = computed(() => `${this.dialogId()}-title`);
  readonly descriptionId = computed(() => `${this.dialogId()}-description`);

  readonly context: DialogContext = {
    open:          this.nOpen,
    persistent:    this.nPersistent,
    role:          this.nRole,
    dialogId:      this.dialogId,
    titleId:       this.titleId,
    descriptionId: this.descriptionId,
    triggerEl:     this._triggerEl.asReadonly(),
    setTriggerEl:  (el) => this._triggerEl.set(el),
    setOpen:       (v) => this._setOpen(v),
    close:         () => this._setOpen(false),
  };

  private _setOpen(value: boolean): void {
    if (this.nOpen() === value) return;
    this.nOpen.set(value);
    this.nOpenChange.emit(value);
  }
}

import { Directive, ElementRef, OnDestroy, inject } from '@angular/core';
import { DIALOG_CONTEXT } from './dialog.context';

@Directive({
  selector: '[n-dialog-trigger]',
  standalone: true,
  host: {
    'data-slot': 'trigger',
    'aria-haspopup': 'dialog',
    '[attr.aria-expanded]': 'ctx.open()',
    '[attr.aria-controls]': 'ctx.open() ? ctx.dialogId() : null',
    '[attr.data-state]': 'ctx.open() ? "open" : "closed"',
    '(click)': 'ctx.setOpen(true)',
  },
})
export class DialogTriggerDirective implements OnDestroy {
  protected readonly ctx = inject(DIALOG_CONTEXT);
  private readonly _host = inject<ElementRef<HTMLElement>>(ElementRef);

  constructor() {
    this.ctx.setTriggerEl(this._host.nativeElement);
  }

  ngOnDestroy(): void {
    this.ctx.setTriggerEl(null);
  }
}

import { A11yModule, FocusTrap, FocusTrapFactory } from '@angular/cdk/a11y';
import { Overlay, OverlayConfig, OverlayRef } from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  TemplateRef,
  ViewChild,
  ViewContainerRef,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DIALOG_CONTEXT } from './dialog.context';
import { dialogContentVariants, type DialogContentVariants } from './dialog.variants';

@Component({
  selector: 'n-dialog-content',
  standalone: true,
  imports: [A11yModule],
  template: `
    <ng-template #panel>
      <!-- Backdrop -->
      <div
        class="fixed inset-0 bg-black/80 transition-opacity duration-150"
        [class.opacity-0]="isClosing()"
        [class.ease-in]="isClosing()"
        data-dialog-backdrop
        aria-hidden="true"
        (click)="handleBackdropClick()"
      ></div>

      <!-- Centering shell -->
      <div class="fixed inset-0 flex items-center justify-center p-4 pointer-events-none">
        <div
          #panelEl
          [id]="ctx.dialogId()"
          [attr.role]="ctx.role()"
          aria-modal="true"
          [attr.aria-labelledby]="ctx.titleId()"
          [attr.aria-describedby]="ctx.descriptionId()"
          [attr.data-size]="nSize()"
          [attr.data-shaking]="shaking() ? '' : null"
          data-slot="content"
          data-dialog
          tabindex="-1"
          [class]="classes()"
          (keydown)="handleKeydown($event)"
          style="pointer-events: auto;"
        >
          @if (!nHideClose()) {
            <button
              type="button"
              class="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background
                     transition-opacity hover:opacity-100 focus:outline-none focus:ring-2
                     focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none"
              aria-label="Fechar"
              (click)="ctx.close()"
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                stroke-linecap="round"
                stroke-linejoin="round"
                aria-hidden="true"
              >
                <path d="M18 6 6 18"/><path d="m6 6 12 12"/>
              </svg>
            </button>
          }
          <ng-content />
        </div>
      </div>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class DialogContentComponent implements AfterViewInit, OnDestroy {
  readonly nSize       = input<DialogContentVariants['nSize']>('default');
  readonly nScrollable = input<boolean>(false);
  readonly nHideClose  = input<boolean>(false);
  readonly nClass      = input<string>('');

  protected readonly ctx             = inject(DIALOG_CONTEXT);
  private readonly _overlay          = inject(Overlay);
  private readonly _vcr              = inject(ViewContainerRef);
  private readonly _focusTrapFactory = inject(FocusTrapFactory);

  @ViewChild('panel', { static: true }) private _panelTpl!: TemplateRef<unknown>;
  @ViewChild('panelEl') private _panelEl?: ElementRef<HTMLElement>;

  private _overlayRef: OverlayRef | null = null;
  private _portal: TemplatePortal | null = null;
  private _focusTrap: FocusTrap | null = null;
  private _detachTimer?: ReturnType<typeof setTimeout>;
  protected readonly shaking   = signal(false);
  protected readonly isClosing = signal(false);

  protected readonly classes = computed(() =>
    mergeClasses(
      dialogContentVariants({ nSize: this.nSize() }),
      this.nScrollable() && 'overflow-hidden',
      this.isClosing() && 'opacity-0 scale-95 ease-in',
      this.nClass(),
    ),
  );

  constructor() {
    effect(() => {
      if (this.ctx.open()) {
        clearTimeout(this._detachTimer);
        this._attach();
      } else if (this._overlayRef) {
        this._beginDetach();
      }
    });
  }

  ngAfterViewInit(): void {
    this._portal = new TemplatePortal(this._panelTpl, this._vcr);
  }

  ngOnDestroy(): void {
    clearTimeout(this._detachTimer);
    this._forceDetach();
  }

  private _attach(): void {
    if (!this._portal || this._overlayRef?.hasAttached()) return;

    const config = new OverlayConfig({
      positionStrategy: this._overlay.position().global(),
      scrollStrategy: this._overlay.scrollStrategies.block(),
      hasBackdrop: false,
      width: '100%',
      height: '100%',
    });

    this._overlayRef = this._overlay.create(config);
    this._overlayRef.attach(this._portal);

    queueMicrotask(() => {
      const el = this._panelEl?.nativeElement;
      if (!el) return;
      this._focusTrap = this._focusTrapFactory.create(el);
      this._focusTrap.focusInitialElementWhenReady();
    });
  }

  private _beginDetach(): void {
    clearTimeout(this._detachTimer);
    this.isClosing.set(true);

    const triggerEl = untracked(() => this.ctx.triggerEl());
    if (triggerEl) triggerEl.focus({ preventScroll: true });

    this._focusTrap?.destroy();
    this._focusTrap = null;

    this._detachTimer = setTimeout(() => {
      this.isClosing.set(false);
      this._forceDetach();
    }, 160);
  }

  private _forceDetach(): void {
    this._overlayRef?.dispose();
    this._overlayRef = null;
  }

  protected handleBackdropClick(): void {
    if (this.ctx.role() === 'alertdialog') return;
    if (this.ctx.persistent()) { this._shake(); return; }
    this.ctx.close();
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (event.key !== 'Escape') return;
    event.preventDefault();
    event.stopPropagation();
    if (this.ctx.role() === 'alertdialog') return;
    if (this.ctx.persistent()) { this._shake(); return; }
    this.ctx.close();
  }

  private _shake(): void {
    this.shaking.set(true);
    setTimeout(() => this.shaking.set(false), 450);
  }
}

import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';

@Component({
  selector: 'n-dialog-header',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'header',
    '[class]': 'classes()',
  },
})
export class DialogHeaderComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('flex flex-col gap-1.5 text-center sm:text-left', this.nClass()),
  );
}

import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';

@Component({
  selector: 'n-dialog-footer',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'footer',
    '[class]': 'classes()',
  },
})
export class DialogFooterComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('flex flex-col-reverse sm:flex-row sm:justify-end sm:gap-2', this.nClass()),
  );
}

import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DIALOG_CONTEXT } from './dialog.context';

@Component({
  selector: 'n-dialog-title',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'title',
    'role': 'heading',
    'aria-level': '2',
    '[id]': 'ctx.titleId()',
    '[class]': 'classes()',
  },
})
export class DialogTitleComponent {
  protected readonly ctx = inject(DIALOG_CONTEXT);
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('text-lg font-semibold leading-none tracking-tight', this.nClass()),
  );
}

import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DIALOG_CONTEXT } from './dialog.context';

@Component({
  selector: 'n-dialog-description',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'description',
    '[id]': 'ctx.descriptionId()',
    '[class]': 'classes()',
  },
})
export class DialogDescriptionComponent {
  protected readonly ctx = inject(DIALOG_CONTEXT);
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('text-sm text-muted-foreground', this.nClass()),
  );
}

import { Directive, inject } from '@angular/core';
import { DIALOG_CONTEXT } from './dialog.context';

@Directive({
  selector: '[n-dialog-close]',
  standalone: true,
  host: {
    'data-slot': 'close',
    '(click)': 'ctx.close()',
  },
})
export class DialogCloseDirective {
  protected readonly ctx = inject(DIALOG_CONTEXT);
}

import { InjectionToken, Signal } from '@angular/core';

export interface DialogContext {
  readonly open: Signal<boolean>;
  readonly persistent: Signal<boolean>;
  readonly role: Signal<'dialog' | 'alertdialog'>;
  readonly dialogId: Signal<string>;
  readonly titleId: Signal<string>;
  readonly descriptionId: Signal<string>;
  readonly triggerEl: Signal<HTMLElement | null>;
  setOpen(value: boolean): void;
  close(): void;
  setTriggerEl(el: HTMLElement | null): void;
}

export const DIALOG_CONTEXT = new InjectionToken<DialogContext>('DIALOG_CONTEXT');

import { cva, type VariantProps } from 'class-variance-authority';

export const dialogContentVariants = cva(
  [
    'relative bg-background rounded-lg shadow-lg border p-6',
    'flex flex-col gap-4',
    'transition-all duration-150 ease-out',
    'opacity-100 scale-100',
  ],
  {
    variants: {
      nSize: {
        sm:      'w-full max-w-sm',
        default: 'w-full max-w-lg',
        lg:      'w-full max-w-2xl',
        xl:      'w-full max-w-4xl',
        full:    'w-screen h-screen max-w-none rounded-none border-none',
      },
    },
    defaultVariants: { nSize: 'default' },
  },
);

export type DialogContentVariants = VariantProps<typeof dialogContentVariants>;

export * from './dialog.component';
export * from './dialog-trigger.directive';
export * from './dialog-content.component';
export * from './dialog-header.component';
export * from './dialog-footer.component';
export * from './dialog-title.component';
export * from './dialog-description.component';
export * from './dialog-close.directive';
export * from './dialog.context';
export * from './dialog.variants';

