import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { DialogCloseDirective } from '../dialog-close.directive';
import { DialogComponent } from '../dialog.component';
import { DialogContentComponent } from '../dialog-content.component';
import { DialogDescriptionComponent } from '../dialog-description.component';
import { DialogFooterComponent } from '../dialog-footer.component';
import { DialogHeaderComponent } from '../dialog-header.component';
import { DialogTitleComponent } from '../dialog-title.component';
import { DialogTriggerDirective } from '../dialog-trigger.directive';

@Component({
  selector: 'demo-dialog-alert',
  standalone: true,
  imports: [
    ButtonComponent,
    DialogComponent,
    DialogTriggerDirective,
    DialogContentComponent,
    DialogHeaderComponent,
    DialogFooterComponent,
    DialogTitleComponent,
    DialogDescriptionComponent,
    DialogCloseDirective,
  ],
  template: `
    <n-dialog nRole="alertdialog">
      <button n-button n-dialog-trigger nVariant="destructive">Deletar conta</button>
      <n-dialog-content nSize="sm" [nHideClose]="true">
        <n-dialog-header>
          <n-dialog-title>Tem certeza absoluta?</n-dialog-title>
          <n-dialog-description>
            Esta ação não pode ser desfeita. Todos os seus dados serão permanentemente
            removidos dos nossos servidores.
          </n-dialog-description>
        </n-dialog-header>
        <n-dialog-footer>
          <button n-button nVariant="outline" n-dialog-close>Cancelar</button>
          <button n-button nVariant="destructive" n-dialog-close>Continuar</button>
        </n-dialog-footer>
      </n-dialog-content>
    </n-dialog>
  `,
})
export class DialogAlertDemo {}

import { Component, signal } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { DialogCloseDirective } from '../dialog-close.directive';
import { DialogComponent } from '../dialog.component';
import { DialogContentComponent } from '../dialog-content.component';
import { DialogDescriptionComponent } from '../dialog-description.component';
import { DialogFooterComponent } from '../dialog-footer.component';
import { DialogHeaderComponent } from '../dialog-header.component';
import { DialogTitleComponent } from '../dialog-title.component';
import { DialogTriggerDirective } from '../dialog-trigger.directive';

@Component({
  selector: 'demo-dialog-default',
  standalone: true,
  imports: [
    ButtonComponent,
    DialogComponent,
    DialogTriggerDirective,
    DialogContentComponent,
    DialogHeaderComponent,
    DialogFooterComponent,
    DialogTitleComponent,
    DialogDescriptionComponent,
    DialogCloseDirective,
  ],
  template: `
    <n-dialog [(nOpen)]="open">
      <button n-button n-dialog-trigger nVariant="outline">Abrir dialog</button>
      <n-dialog-content>
        <n-dialog-header>
          <n-dialog-title>Editar perfil</n-dialog-title>
          <n-dialog-description>
            Faça alterações no seu perfil aqui. Clique em salvar quando terminar.
          </n-dialog-description>
        </n-dialog-header>
        <div class="grid gap-4 py-4">
          <p class="text-sm text-muted-foreground">Conteúdo do formulário aqui.</p>
        </div>
        <n-dialog-footer>
          <button n-button nVariant="outline" n-dialog-close>Cancelar</button>
          <button n-button (nClick)="save()">Salvar</button>
        </n-dialog-footer>
      </n-dialog-content>
    </n-dialog>
  `,
})
export class DialogDefaultDemo {
  open = signal(false);

  save(): void {
    this.open.set(false);
  }
}

import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { DialogCloseDirective } from '../dialog-close.directive';
import { DialogComponent } from '../dialog.component';
import { DialogContentComponent } from '../dialog-content.component';
import { DialogDescriptionComponent } from '../dialog-description.component';
import { DialogFooterComponent } from '../dialog-footer.component';
import { DialogHeaderComponent } from '../dialog-header.component';
import { DialogTitleComponent } from '../dialog-title.component';
import { DialogTriggerDirective } from '../dialog-trigger.directive';

@Component({
  selector: 'demo-dialog-scrollable',
  standalone: true,
  imports: [
    ButtonComponent,
    DialogComponent,
    DialogTriggerDirective,
    DialogContentComponent,
    DialogHeaderComponent,
    DialogFooterComponent,
    DialogTitleComponent,
    DialogDescriptionComponent,
    DialogCloseDirective,
  ],
  template: `
    <n-dialog>
      <button n-button n-dialog-trigger nVariant="outline">Dialog com scroll</button>
      <n-dialog-content [nScrollable]="true" nClass="max-h-[80vh]">
        <n-dialog-header>
          <n-dialog-title>Termos de Serviço</n-dialog-title>
          <n-dialog-description>
            Leia os termos com atenção antes de aceitar.
          </n-dialog-description>
        </n-dialog-header>
        <div class="overflow-y-auto flex-1 py-4 pr-2">
          @for (i of items; track i) {
            <p class="text-sm text-muted-foreground mb-4">
              Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod
              tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam,
              quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat.
            </p>
          }
        </div>
        <n-dialog-footer>
          <button n-button nVariant="outline" n-dialog-close>Recusar</button>
          <button n-button n-dialog-close>Aceitar</button>
        </n-dialog-footer>
      </n-dialog-content>
    </n-dialog>
  `,
})
export class DialogScrollableDemo {
  readonly items = Array.from({ length: 20 }, (_, i) => i);
}

import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { DialogCloseDirective } from '../dialog-close.directive';
import { DialogComponent } from '../dialog.component';
import { DialogContentComponent } from '../dialog-content.component';
import { DialogDescriptionComponent } from '../dialog-description.component';
import { DialogHeaderComponent } from '../dialog-header.component';
import { DialogTitleComponent } from '../dialog-title.component';
import { DialogTriggerDirective } from '../dialog-trigger.directive';
import { type DialogContentVariants } from '../dialog.variants';

@Component({
  selector: 'demo-dialog-sizes',
  standalone: true,
  imports: [
    ButtonComponent,
    DialogComponent,
    DialogTriggerDirective,
    DialogContentComponent,
    DialogHeaderComponent,
    DialogTitleComponent,
    DialogDescriptionComponent,
    DialogCloseDirective,
  ],
  template: `
    <div class="flex flex-wrap gap-2">
      @for (size of sizes; track size) {
        <n-dialog>
          <button n-button n-dialog-trigger nVariant="outline">{{ size }}</button>
          <n-dialog-content [nSize]="size">
            <n-dialog-header>
              <n-dialog-title>Tamanho: {{ size }}</n-dialog-title>
              <n-dialog-description>
                Este dialog usa nSize="{{ size }}".
              </n-dialog-description>
            </n-dialog-header>
            <div class="py-4">
              <p class="text-sm text-muted-foreground">Conteúdo do dialog.</p>
            </div>
            <div class="flex justify-end">
              <button n-button n-dialog-close>Fechar</button>
            </div>
          </n-dialog-content>
        </n-dialog>
      }
    </div>
  `,
})
export class DialogSizesDemo {
  readonly sizes: DialogContentVariants['nSize'][] = ['sm', 'default', 'lg', 'xl', 'full'];
}

import { Component, signal } from '@angular/core';
import { FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ButtonComponent } from '../../button/button.component';
import { InputComponent } from '../../input/input.component';
import { DialogCloseDirective } from '../dialog-close.directive';
import { DialogComponent } from '../dialog.component';
import { DialogContentComponent } from '../dialog-content.component';
import { DialogDescriptionComponent } from '../dialog-description.component';
import { DialogFooterComponent } from '../dialog-footer.component';
import { DialogHeaderComponent } from '../dialog-header.component';
import { DialogTitleComponent } from '../dialog-title.component';
import { DialogTriggerDirective } from '../dialog-trigger.directive';

@Component({
  selector: 'demo-dialog-with-form',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    ButtonComponent,
    InputComponent,
    DialogComponent,
    DialogTriggerDirective,
    DialogContentComponent,
    DialogHeaderComponent,
    DialogFooterComponent,
    DialogTitleComponent,
    DialogDescriptionComponent,
    DialogCloseDirective,
  ],
  template: `
    <n-dialog [(nOpen)]="open" [nPersistent]="true">
      <button n-button n-dialog-trigger>Editar perfil</button>
      <n-dialog-content>
        <n-dialog-header>
          <n-dialog-title>Editar perfil</n-dialog-title>
          <n-dialog-description>
            Alterações não salvas serão perdidas. Clique fora para ver o shake.
          </n-dialog-description>
        </n-dialog-header>

        <form
          [formGroup]="form"
          (ngSubmit)="submit()"
          class="grid gap-4 py-4"
          id="edit-profile-form"
        >
          <n-input formControlName="name" nLabel="Nome" [nRequired]="true" />
          <n-input formControlName="email" nLabel="E-mail" nType="email" [nRequired]="true" />
          <n-input formControlName="username" nLabel="Nome de usuário" />
        </form>

        <n-dialog-footer>
          <button n-button nVariant="outline" n-dialog-close type="button">Cancelar</button>
          <button
            n-button
            type="submit"
            form="edit-profile-form"
            [nDisabled]="form.invalid"
          >
            Salvar alterações
          </button>
        </n-dialog-footer>
      </n-dialog-content>
    </n-dialog>

    @if (lastSaved()) {
      <p class="text-sm text-muted-foreground mt-4">
        Salvo: {{ lastSaved()?.name }} &lt;{{ lastSaved()?.email }}&gt;
      </p>
    }
  `,
})
export class DialogWithFormDemo {
  open = signal(false);
  lastSaved = signal<{ name: string; email: string; username: string } | null>(null);

  readonly form = new FormGroup({
    name:     new FormControl('', { nonNullable: true, validators: [Validators.required] }),
    email:    new FormControl('', { nonNullable: true, validators: [Validators.required, Validators.email] }),
    username: new FormControl('', { nonNullable: true }),
  });

  submit(): void {
    if (this.form.invalid) return;
    this.lastSaved.set(this.form.getRawValue());
    this.open.set(false);
  }
}
